const env = require('frontend-env');

const defaults = require('../../config/defaults');

// At least 3 chars, lowercase alphanumeric, no leading hyphen.
const MELI_DOMAIN_REGEX = /^[a-z0-9][a-z0-9-]{2,}$/;

/**
 * Resolves the final `baseURL` from a RestClient config.
 *
 * - If `meliDomain` is set, builds the URL from it (Fury/sandbox →
 *   melisystems.com, otherwise → melioffice.com). Throws if `baseURL` is also
 *   set, or if the value doesn't match the Fury naming format.
 * - Otherwise, returns the explicit `baseURL` or falls back to the default.
 *
 * @param {object} config
 * @param {string} [config.baseURL]
 * @param {string} [config.meliDomain]
 * @returns {string}
 */
function resolveBaseURL({ baseURL, meliDomain }) {
  if (meliDomain) {
    if (baseURL) {
      throw new Error(
        '[restclient] "meliDomain" and "baseURL" are mutually exclusive. Set only one.',
      );
    }

    if (!MELI_DOMAIN_REGEX.test(meliDomain)) {
      throw new Error(
        `[restclient] Invalid "meliDomain" value: ${meliDomain}. ` +
          'Allowed: lowercase letters, numbers, and hyphens.',
      );
    }

    return (env.FURY || env.SANDBOX) && !env.IS_CI
      ? `http://${meliDomain}.melisystems.com`
      : `https://${meliDomain}.melioffice.com`;
  }

  return baseURL || defaults.baseURL;
}

exports.resolveBaseURL = resolveBaseURL;
